<?php
namespace app\Services; use app\Repositories\ReturnRepository; use app\Repositories\BorrowRepository; use app\Repositories\InventoryRepository; use app\Repositories\Database; use app\Requests\Validator;
class ReturnService{ private ReturnRepository $returns; private BorrowRepository $borrows; private InventoryRepository $items; public function __construct(){ $this->returns=new ReturnRepository(); $this->borrows=new BorrowRepository(); $this->items=new InventoryRepository(); } public function all($date=''){return $this->returns->all($date);} public function find($id){return $this->returns->find((int)$id);} public function calculateFine(string $dueDate,string $returnDate):int{ $days=(strtotime($returnDate)-strtotime($dueDate))/86400; return $days>0?(int)$days*FINE_PER_DAY:0; } public function create(array $d):array{ $e=Validator::required($d,['borrow_id'=>'Phiếu mượn','return_date'=>'Ngày trả']); if($e)return ['ok'=>false,'errors'=>$e]; $borrow=$this->borrows->find((int)$d['borrow_id']); if(!$borrow)return ['ok'=>false,'message'=>'Phiếu mượn không tồn tại']; if($borrow['status']!=='borrowing')return ['ok'=>false,'message'=>'Phiếu này đã được trả']; if($this->returns->existsForBorrow((int)$d['borrow_id']))return ['ok'=>false,'message'=>'Phiếu này đã có phiếu trả']; $fine=$this->calculateFine($borrow['due_date'],$d['return_date']); $pdo=Database::connection(); try{$pdo->beginTransaction(); $id=$this->returns->create(['borrow_id'=>$d['borrow_id'],'return_date'=>$d['return_date'],'fine_amount'=>$fine,'note'=>$d['note']??null,'created_by'=>$d['created_by']??null]); $this->borrows->updateStatus((int)$d['borrow_id'],'returned'); $this->items->increase($borrow['item_type'],(int)$borrow['item_id']); $pdo->commit(); return ['ok'=>true,'data'=>$this->find($id)];}catch(\Throwable $ex){$pdo->rollBack();return ['ok'=>false,'message'=>'Lỗi trả tài liệu: '.$ex->getMessage()];}} public function undo(int $returnId):array{ $r=$this->find($returnId); if(!$r)return ['ok'=>false,'message'=>'Phiếu trả không tồn tại']; $item=$this->items->findItem($r['item_type'],(int)$r['item_id']); if(!$item||$item['quantity']<=0)return ['ok'=>false,'message'=>'Không thể hoàn tác vì số lượng tài liệu hiện không đủ để trừ lại']; $pdo=Database::connection(); try{$pdo->beginTransaction(); $this->items->decrease($r['item_type'],(int)$r['item_id']); $this->borrows->updateStatus((int)$r['borrow_id'],'borrowing'); $this->returns->delete($returnId); $pdo->commit(); return ['ok'=>true];}catch(\Throwable $ex){$pdo->rollBack();return ['ok'=>false,'message'=>'Lỗi hoàn tác: '.$ex->getMessage()];}}}
